import React, { useState, useEffect, useRef } from 'react';
import { messagesAPI } from '../../utils/api';
import './MessageSender.css';

const MessageSender = ({ 
  groupId, 
  onMessageSent, 
  currentUser,
  replyTo = null,
  onReplyCancel = null 
}) => {
  const [content, setContent] = useState('');
  const [recipientId, setRecipientId] = useState('');
  const [secondaryRecipientId, setSecondaryRecipientId] = useState('');
  const [recipients, setRecipients] = useState([]);
  const [assignmentInfo, setAssignmentInfo] = useState(null);
  const [loading, setLoading] = useState(false);
  const [loadingRecipients, setLoadingRecipients] = useState(false);
  const [showSecondaryOption, setShowSecondaryOption] = useState(false);
  const [showRecipientDropdown, setShowRecipientDropdown] = useState(false);
  const [showTaskPopup, setShowTaskPopup] = useState(false);
  const fileInputRef = useRef(null);
  const textareaRef = useRef(null);

  // 📋 Load available recipients
  useEffect(() => {
    if (groupId) {
      loadRecipients();
    }
  }, [groupId]);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = Math.min(textareaRef.current.scrollHeight, 120) + 'px';
    }
  }, [content]);

  const loadRecipients = async () => {
    setLoadingRecipients(true);
    try {
      const data = await messagesAPI.getRecipients(groupId);
      setRecipients(data.recipients || []);
    } catch (error) {
      console.error('Failed to load recipients:', error);
    } finally {
      setLoadingRecipients(false);
    }
  };

  const loadAssignmentInfo = async (recipientId) => {
    try {
      const info = await messagesAPI.getAssignmentInfo(groupId, recipientId);
      setAssignmentInfo(info);
      setShowSecondaryOption(info.isAssigned && info.secondaryUsers.length > 0);
    } catch (error) {
      console.error('Failed to load assignment info:', error);
      setAssignmentInfo(null);
      setShowSecondaryOption(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      if (!recipientId) {
        alert('Please select a recipient before sending message.');
        return;
      }

      if (!content || !content.trim()) {
        alert('Please enter a message.');
        return;
      }

      setLoading(true);

      const messageData = {
        content: content.trim(),
        recipient_id: parseInt(recipientId),
        secondary_recipient_id: secondaryRecipientId ? parseInt(secondaryRecipientId) : null,
        reply_to_id: replyTo?.id || null
      };

      const response = await messagesAPI.sendMessage(groupId, messageData);

      setContent('');
      setRecipientId('');
      setSecondaryRecipientId('');
      setShowSecondaryOption(false);
      setAssignmentInfo(null);

      if (onMessageSent) {
        onMessageSent(response.message);
      }

      if (onReplyCancel) {
        onReplyCancel();
      }

    } catch (error) {
      console.error('❌ Message send error:', error);
      alert(error?.error || 'Failed to send message');
    } finally {
      setLoading(false);
    }
  };

  const handleReplyCancel = () => {
    if (onReplyCancel) {
      onReplyCancel();
    }
  };

  const handleFileSelect = () => {
    fileInputRef.current?.click();
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit(e);
    }
  };

  const getSelectedRecipientName = () => {
    const recipient = recipients.find(r => r.user_id.toString() === recipientId);
    return recipient ? recipient.full_name : '';
  };

  return (
    <div className="modern-message-sender">
      {/* Reply To Indicator */}
      {replyTo && (
        <div className="reply-indicator">
          <div className="reply-content">
            <span className="reply-label">Reply to {replyTo.sender_name}:</span>
            <span className="reply-text">{replyTo.content?.substring(0, 50)}...</span>
          </div>
          <button type="button" className="reply-cancel" onClick={handleReplyCancel}>
            ✕
          </button>
        </div>
      )}

      {/* Recipient Selection */}
      <div className="recipient-selector">
        <div 
          className={`recipient-input ${recipientId ? 'has-selection' : ''}`}
          onClick={() => setShowRecipientDropdown(!showRecipientDropdown)}
        >
          {recipientId ? (
            <div className="selected-recipient">
              <span className="recipient-icon">👤</span>
              <span className="recipient-name">{getSelectedRecipientName()}</span>
              <span className="recipient-arrow">▼</span>
            </div>
          ) : (
            <div className="placeholder-recipient">
              <span className="recipient-icon">👤</span>
              <span className="placeholder-text">Select recipient *</span>
              <span className="recipient-arrow">▼</span>
            </div>
          )}
        </div>

        {showRecipientDropdown && (
          <div className="recipient-dropdown">
            {loadingRecipients ? (
              <div className="loading-recipients">Loading...</div>
            ) : (
              recipients.map((recipient) => (
                <div
                  key={recipient.user_id}
                  className={`recipient-option ${recipient.user_id.toString() === recipientId ? 'selected' : ''}`}
                  onClick={() => {
                    setRecipientId(recipient.user_id.toString());
                    setShowRecipientDropdown(false);
                    loadAssignmentInfo(recipient.user_id.toString());
                  }}
                >
                  <span className="recipient-avatar">
                    {recipient.full_name.charAt(0).toUpperCase()}
                  </span>
                  <div className="recipient-info">
                    <span className="recipient-fullname">{recipient.full_name}</span>
                    <span className="recipient-role">
                      {recipient.role || recipient.crm_role || 'User'}
                    </span>
                  </div>
                </div>
              ))
            )}
          </div>
        )}
      </div>

      {/* Secondary Recipient (Manager) */}
      {showSecondaryOption && assignmentInfo?.secondaryUsers?.length > 0 && (
        <div className="secondary-recipient">
          <div className="secondary-label">🔗 Also notify:</div>
          <select
            className="secondary-select"
            value={secondaryRecipientId}
            onChange={(e) => setSecondaryRecipientId(e.target.value)}
          >
            <option value="">Optional: Add manager</option>
            {assignmentInfo.secondaryUsers.map((user) => (
              <option key={user.id} value={user.id}>
                {user.full_name} ({user.readable_role || user.role})
              </option>
            ))}
          </select>
        </div>
      )}

      {/* Message Input */}
      <form onSubmit={handleSubmit} className="message-form">
        <div className="message-input-container">
          {/* Action Buttons */}
          <div className="input-actions">
            <button
              type="button"
              className="action-btn attachment-btn"
              onClick={handleFileSelect}
              title="Attach file"
            >
              📎
            </button>
            <input
              ref={fileInputRef}
              type="file"
              style={{ display: 'none' }}
              onChange={(e) => {
                // Handle file upload
                console.log('File selected:', e.target.files);
              }}
            />
            <button
              type="button"
              className="action-btn task-btn"
              onClick={() => setShowTaskPopup(!showTaskPopup)}
              title="Create task"
            >
              ✅
            </button>
            <button
              type="button"
              className="action-btn voice-btn"
              title="Voice message"
            >
              🎤
            </button>
          </div>

          {/* Message Textarea */}
          <div className="message-input-wrapper">
            <textarea
              ref={textareaRef}
              className="message-textarea"
              value={content}
              onChange={(e) => setContent(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="Type a message..."
              rows={1}
              disabled={loading}
            />
          </div>

          {/* Send Button */}
          <button
            type="submit"
            className={`send-btn ${content.trim() && recipientId ? 'active' : ''}`}
            disabled={loading || !content.trim() || !recipientId}
            title={content.trim() && recipientId ? 'Send message' : 'Select recipient and type message'}
          >
            {loading ? (
              <span className="loading-spinner">⏳</span>
            ) : (
              <span className="send-icon">➤</span>
            )}
          </button>
        </div>
      </form>

      {/* Task Popup */}
      {showTaskPopup && (
        <div className="task-popup">
          <div className="task-popup-content">
            <h4>Create Task</h4>
            <p>Task creation feature coming soon...</p>
            <button onClick={() => setShowTaskPopup(false)}>Close</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default MessageSender;
